typedef struct {
    MakoChan* *data;
    size_t len;
    size_t cap;
} MakoArr_chan_int;
static inline MakoArr_chan_int mako_arr_chan_int_make(int64_t len, int64_t cap) {
    if (len < 0) len = 0;
    if (cap < len) cap = len;
    MakoArr_chan_int a;
    a.data = (MakoChan* *)calloc((size_t)(cap ? cap : 1), sizeof(MakoChan*));
    a.len = (size_t)len;
    a.cap = (size_t)(cap ? cap : 1);
    return a;
}
static inline int64_t mako_arr_chan_int_len(MakoArr_chan_int a) { return (int64_t)a.len; }
static inline int64_t mako_arr_chan_int_cap(MakoArr_chan_int a) { return (int64_t)a.cap; }
static inline MakoChan* mako_arr_chan_int_get(MakoArr_chan_int a, int64_t i) {
    if (i < 0 || (size_t)i >= a.len) mako_abort("nested slice index out of bounds");
    return a.data[i];
}
static inline void mako_arr_chan_int_set(MakoArr_chan_int a, int64_t i, MakoChan* v) {
    if (i < 0 || (size_t)i >= a.len) mako_abort("nested slice index out of bounds");
    a.data[i] = v;
}
static inline MakoArr_chan_int mako_arr_chan_int_append(MakoArr_chan_int s, MakoChan* v) {
    if (s.len + 1 > s.cap) {
        size_t ncap = s.cap ? s.cap * 2 : 1;
        if (ncap < s.len + 1) ncap = s.len + 1;
        MakoChan* *nd = (MakoChan* *)realloc(s.data, ncap * sizeof(MakoChan*));
        if (!nd) mako_abort("append: out of memory");
        s.data = nd; s.cap = ncap;
    }
    s.data[s.len++] = v; return s;
}
static inline MakoArr_chan_int mako_arr_chan_int_of(const MakoChan* *vals, size_t n) {
    MakoArr_chan_int a = mako_arr_chan_int_make((int64_t)n, (int64_t)n);
    if (n) memcpy(a.data, vals, n * sizeof(MakoChan*));
    return a;
}
static inline MakoArr_chan_int mako_arr_chan_int_slice_expr(MakoArr_chan_int s, int64_t low, int64_t high, int64_t max, int has_max) {
    int64_t len = (int64_t)s.len;
    int64_t cap = (int64_t)s.cap;
    if (low < 0) low = 0;
    if (high < 0) high = 0;
    if (low > len) low = len;
    if (high > len) high = len;
    if (high < low) high = low;
    MakoArr_chan_int out;
    out.data = s.data + (size_t)low;
    out.len = (size_t)(high - low);
    if (has_max) {
        if (max < high) max = high;
        if (max > cap) max = cap;
        if (max < low) max = low;
        out.cap = (size_t)(max - low);
    } else {
        out.cap = (size_t)(cap - low);
    }
    return out;
}
